mapper.select:
SELECT * from crisis_report c  left join student_info s on c.student_id = s.student_id


        AND c.crisis_level = #{crisisLevel}


        AND s.college_id = #{college}


        AND c.report_status = #{reportStatus}

SELECT c.report_id AS id, c.crisis_level AS level, CASE c.crisis_level WHEN 'SEVERE' THEN '红色' WHEN 'HIGH' THEN '橙色' WHEN 'MODERATE' THEN '黄色' WHEN 'LOW' THEN '蓝色' ELSE '未知' END AS levelText, u.real_name AS studentName, si.student_number AS studentId, o.org_name AS collegeName, si.class_id AS className, DATE_FORMAT(c.created_at, '%Y-%m-%d') AS reportDate, c.incident_description AS description, c.report_status AS status, CASE c.report_status WHEN 'PENDING' THEN '待审批' WHEN 'REVIEWING' THEN '处理中' WHEN 'PROCESSED' THEN '已处理' WHEN 'CLOSED' THEN '已结案' ELSE '未知' END AS statusText, ru.real_name AS handler FROM crisis_report c JOIN student_info si ON c.student_id = si.student_id JOIN user u ON si.user_id = u.user_id LEFT JOIN organization o ON si.college_id = o.org_id LEFT JOIN user ru ON c.reviewer_id = ru.user_id
AND (u.real_name LIKE CONCAT('%', #{keyword}, '%') OR si.student_number LIKE CONCAT('%', #{keyword}, '%'))
AND si.college_id = #{college}
AND c.crisis_level = #{level}
AND c.report_status = #{status}
AND c.created_at >= #{startDate}
AND c.created_at <= #{endDate}
ORDER BY c.created_at DESC
